wwv_flow_imp_shared.create_plugin(
 p_id=>wwv_flow_imp.id(9480774346102774)
,p_plugin_type=>'REGION TYPE'
,p_name=>'COM.THAPLIYALRAVI.ECHARTS_REGION'
,p_display_name=>'ECharts Region'
,p_javascript_file_urls=>wwv_flow_string.join(wwv_flow_t_varchar2(
'#PLUGIN_FILES#echarts.min.js',
'#PLUGIN_FILES#echarts-region.js'))
,p_css_file_urls=>'#PLUGIN_FILES#echarts-region.css'
,p_plsql_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'function render (',
'  p_region              in apex_plugin.t_region,',
'  p_plugin              in apex_plugin.t_plugin,',
'  p_is_printer_friendly in boolean',
') return apex_plugin.t_region_render_result is',
'  l_result     apex_plugin.t_region_render_result;',
'  l_chart_type varchar2(50)  := nvl(p_region.attribute_01, ''pie'');',
'  l_title      varchar2(400) := p_region.attribute_02;',
'  l_height     varchar2(10)  := nvl(p_region.attribute_03, ''400'');',
'  l_color      varchar2(50)  := nvl(p_region.attribute_04, ''default'');',
'  l_legend     varchar2(10)  := p_region.attribute_05;',
'  l_nodata     varchar2(400) := nvl(p_region.attribute_07, ''No data found.'');',
'  l_xlabel     varchar2(200) := p_region.attribute_08;',
'  l_ylabel     varchar2(200) := p_region.attribute_09;',
'  l_anim       varchar2(20)  := nvl(p_region.attribute_10, ''normal'');',
'  l_brad       varchar2(10)  := nvl(p_region.attribute_11, ''4'');',
'  l_click      varchar2(10)  := p_region.attribute_13;',
'  l_legpos     varchar2(20)  := nvl(p_region.attribute_14, ''bottom'');',
'  l_show_lbl   varchar2(10)  := p_region.attribute_15;',
'  l_region_id  varchar2(200);',
'  l_ajax_id    varchar2(200);',
'  l_canvas_id  varchar2(200);',
'  l_js         varchar2(32767);',
'begin',
'  if p_region.static_id is null then',
'    sys.htp.p(''<div class="echarts-region-error">ECharts Region: Please set a Static ID on this region.</div>'');',
'    return l_result;',
'  end if;',
'  l_region_id := apex_escape.html_attribute(p_region.static_id);',
'  l_ajax_id   := apex_plugin.get_ajax_identifier;',
'  l_canvas_id := ''echarts_cvs_'' || l_region_id;',
'  sys.htp.p(''<div class="echarts-region-wrap" id="'' || l_region_id || ''">'');',
'  sys.htp.p(''<div class="echarts-region-canvas" id="'' || l_canvas_id || ''" style="height:'' || apex_escape.html_attribute(l_height) || ''px;"></div>'');',
'  sys.htp.p(''</div>'');',
'  l_js := ''apex.server.plugin("'' || l_ajax_id || ''",{pageItems:"'';',
'  l_js := l_js || apex_plugin_util.page_item_names_to_jquery(p_region.ajax_items_to_submit);',
'  l_js := l_js || ''"},{dataType:"json",success:function(pData){'';',
'  l_js := l_js || ''THAPLIYALRAVI.EChartsRegion.render(pData,{'';',
'  l_js := l_js || ''"regionId":"''   || l_region_id  || ''",'';',
'  l_js := l_js || ''"chartType":"''  || l_chart_type || ''",'';',
'  l_js := l_js || ''"title":"''      || l_title      || ''",'';',
'  l_js := l_js || ''"colorTheme":"'' || l_color      || ''",'';',
'  l_js := l_js || ''"showLegend":"'' || l_legend     || ''",'';',
'  l_js := l_js || ''"showLabels":"'' || l_show_lbl   || ''",'';',
'  l_js := l_js || ''"noDataMsg":"''  || l_nodata     || ''",'';',
'  l_js := l_js || ''"xLabel":"''     || l_xlabel     || ''",'';',
'  l_js := l_js || ''"yLabel":"''     || l_ylabel     || ''",'';',
'  l_js := l_js || ''"animation":"''  || l_anim       || ''",'';',
'  l_js := l_js || ''"barRadius":"''  || l_brad       || ''",'';',
'  l_js := l_js || ''"fireClick":"''  || l_click      || ''",'';',
'  l_js := l_js || ''"legendPos":"''  || l_legpos     || ''"'';',
'  l_js := l_js || ''});},error:function(jqXHR,ts,et){'';',
'  l_js := l_js || ''document.getElementById("'' || l_canvas_id || ''").innerHTML='';',
'  l_js := l_js || ''"<div class=echarts-region-error>Error: "+ts+"</div>";}})''  ;',
'  apex_javascript.add_onload_code(p_code => l_js);',
'  return l_result;',
'end render;',
'',
'function ajax (',
'  p_region in apex_plugin.t_region,',
'  p_plugin in apex_plugin.t_plugin',
') return apex_plugin.t_region_ajax_result is',
'  l_result    apex_plugin.t_region_ajax_result;',
'  l_query     varchar2(32767) := p_region.source;',
'  l_col_count pls_integer;',
'  l_cur       integer;',
'  l_dummy     integer;',
'  l_label     varchar2(4000);',
'  l_value     number;',
'  l_series    varchar2(4000);',
'  l_desc      dbms_sql.desc_tab;',
'begin',
'  l_cur := dbms_sql.open_cursor;',
'  dbms_sql.parse(l_cur, l_query, dbms_sql.native);',
'  dbms_sql.describe_columns(l_cur, l_col_count, l_desc);',
'  dbms_sql.define_column(l_cur, 1, l_label, 4000);',
'  dbms_sql.define_column(l_cur, 2, l_value);',
'  if l_col_count >= 3 then',
'    dbms_sql.define_column(l_cur, 3, l_series, 4000);',
'  end if;',
'  l_dummy := dbms_sql.execute(l_cur);',
'  apex_json.open_object;',
'  apex_json.open_array(''rows'');',
'  while dbms_sql.fetch_rows(l_cur) > 0 loop',
'    dbms_sql.column_value(l_cur, 1, l_label);',
'    dbms_sql.column_value(l_cur, 2, l_value);',
'    if l_col_count >= 3 then',
'      dbms_sql.column_value(l_cur, 3, l_series);',
'    else',
'      l_series := ''__single__'';',
'    end if;',
'    apex_json.open_object;',
'    apex_json.write(''label'',  l_label);',
'    apex_json.write(''value'',  l_value);',
'    apex_json.write(''series'', l_series);',
'    apex_json.write(''name'',   l_label);',
'    apex_json.close_object;',
'  end loop;',
'  apex_json.close_array;',
'  apex_json.close_object;',
'  dbms_sql.close_cursor(l_cur);',
'  return l_result;',
'exception',
'  when others then',
'    if dbms_sql.is_open(l_cur) then dbms_sql.close_cursor(l_cur); end if;',
'    apex_json.open_object;',
'    apex_json.write(''error'', sqlerrm);',
'    apex_json.open_array(''rows'');',
'    apex_json.close_array;',
'    apex_json.close_object;',
'    return l_result;',
'end ajax;'))
,p_api_version=>1
,p_render_function=>'render'
,p_ajax_function=>'ajax'
,p_standard_attributes=>'SOURCE_SQL:AJAX_ITEMS_TO_SUBMIT:NO_DATA_FOUND_MESSAGE'
